<template><view class="page"><AppCard title="声音克隆"><view class="subtitle">录制20-30秒清晰语音，需本人授权。</view><view v-for="x in items" :key="x.id" class="list-item">{{x.persona||'未绑定'}} · {{x.status}}</view><button class="btn" @click="create">创建测试克隆任务</button></AppCard></view></template><script setup lang="ts">import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import AppCard from'@/components/AppCard.vue';import{qingxierApi}from'@/services/api';const items=ref<any[]>([]);async function load(){items.value=await qingxierApi.voiceClones()}onShow(load);async function create(){await qingxierApi.createVoiceClone({sampleUrl:'https://cdn.example.com/sample.wav',consentRecord:'已确认本人授权',persona:'mom'});await load()}</script>
